    for path in Path(basedir).rglob('*'):
        if path.is_file() and exts.search(path.suffix):
            os.chmod(path, 0o777)
            if search_file(path, query):
                print("Found in", path)

def search_file(path, query):
    with open(path) as f:
        for line in f:
            if query in line:
                return True
    return False

if __name__ == '__main__':
    import sys
    query = sys.argv[1]
    basedir = sys.argv[2]
    search(basedir, query)

